definition.script:
pipeline {
    agent any

    parameters {
        // FIXED: Changed 'defaultvalue' to 'defaultValue'
        string(name: 'DEPLOY_ENV', defaultValue: 'dev', description: 'environment to deploy to')
        // FIXED: Changed 'defaultvalue' to 'defaultValue' AND added quotes around 'RUN_TESTS'
        booleanParam(name: 'RUN_TESTS', defaultValue: true, description: 'Run Tests ?')
    }

    environment {
        REGION = 'ap-south-1'
        BUILD_VERSION = "1.0.${env.BUILD_NUMBER}" // OPTIONAL: Added a dot for cleaner formatting (1.0.1)
    }

    stages {
        stage('Built-In-Vars') {
            steps {
                echo "Build Number: ${env.BUILD_NUMBER}"
                echo "Build ID: ${env.BUILD_ID}"
                echo "Job Name: ${env.JOB_NAME}"
                echo "Build URL: ${env.BUILD_URL}"
                echo "Workspace: ${env.WORKSPACE}"
                echo "Node Name: ${env.NODE_NAME}"
            }
        }
        stage('Pipeline Parameters') {
            steps {
                echo "Deploy Env: ${params.DEPLOY_ENV}"
                echo "RUN Tests: ${params.RUN_TESTS}"
            }
        }
        stage('Custom Vars') {
            steps {
                echo "REGION: ${env.REGION}"
                echo "BUILD_VERSION: ${env.BUILD_VERSION}"
            }
        }
        stage('Dynamic Custom Vars') {
            steps {
                script {
                    env.RUNTIME_VAR = "runtime-${env.BUILD_NUMBER}"
                    echo "DYNAMIC: ${env.RUNTIME_VAR}"
                }
            }
        }
    }
}
